-- Part 4: 话术库 (50条, 5个分类, 覆盖各种场景)
-- ============================================================
INSERT INTO topics (id, title, description, category, author_user_id, solved, created_at, updated_at) VALUES
-- 攻略区兼话术库: 50条话术, 5个分类
-- category: 邀约/沟通/跟进/转化/其他
(1,  '如何跟大一新生破冰', '同学你好！我是YouSells的学习规划师。听说你对计算机方向感兴趣？其实现在很多大一同学都在提前规划, 因为大一大二的课程和实际工作需求之间还是有不小的差距, 提前接触能让你在求职时更有竞争力。', '邀约', 1, 0, NOW(), NOW()),
(2,  '校园地推话术: 食堂场景', '同学打扰一下, 我是YouSells的。你是什么专业的呀？哦计算机啊, 那你现在有在学习编程吗？我们这边有个免费的编程能力测评, 可以帮你了解自己的水平, 大概3分钟就能完成, 要试试吗？', '邀约', 1, 0, NOW(), NOW()),
(3,  '知乎私信引流话术', '同学你好, 看到你在知乎上问关于转行计算机的问题。我这边是专业做IT培训的, 有很多转行成功的案例。如果你方便的话可以加个微信聊聊, 我可以分享一些学习资料和路线图给你~', '邀约', 1, 0, NOW(), NOW()),
(4,  '线下讲座邀约话术', '这周五下午我们有一场关于AI行业前景的线上分享会, 邀请了BAT的算法工程师来分享。我这边帮你预留了一个名额, 你有兴趣的话我把会议链接发你？', '邀约', 1, 0, NOW(), NOW()),
(5,  '节日问候+软性邀约', '新年快乐！新的一年你有没有考虑过学一门编程语言呢？Python是今年最热门的技术方向, 我这边有份入门资料可以分享给你, 不管报不报课都可以先了解一下~', '邀约', 1, 0, NOW(), NOW()),
(6,  '转介绍开口话术', '小明你好, 我是你的朋友小红推荐的。她说你对编程有兴趣？我们都是做IT教育的, 已经帮很多同学找到了满意的工作。你有空的话可以来我们校区看看, 实地感受一下。', '邀约', 2, 0, NOW(), NOW()),
(7,  '首次面谈: 了解需求', '同学你好, 今天见面聊聊天, 主要是想了解一下你目前的学习情况和未来的想法。你觉得自己的编程基础怎么样？有没有具体想做的方向？', '沟通', 1, 0, NOW(), NOW()),
(8,  '介绍课程体系', '我们的课程分为三个阶段: 第一阶段打基础, 第二阶段做项目, 第三阶段就业辅导。每个阶段都有对应的实战项目, 确保你学完就能直接写在简历上。', '沟通', 1, 0, NOW(), NOW()),
(9,  '解答"学不会"顾虑', '学习编程最重要的是方法和节奏。我们的老师会根据你的基础调整进度, 而且每节课都有课后练习和答疑。目前为止我们还没有遇到过认真学却学不会的同学。', '沟通', 1, 0, NOW(), NOW()),
(10, '解答"价格贵"顾虑', '我理解你的顾虑。不过你可以这样看: 它是一种投资收益。我们的学员平均薪资涨幅在30%以上, 基本上课程费用在入职后两三个月就能回本。而且我们支持分期付款, 可以减轻一次性支付的压力。', '沟通', 1, 0, NOW(), NOW()),
(11, '解答"没时间"顾虑', '我完全理解, 大学课程确实很忙。但正因为忙, 才更需要高效的学习方式。我们每周大概4-6小时的学习量, 周末集中上课, 不会和日常课程冲突。很多同学都是大二大三同时上课和学编程的。', '沟通', 1, 0, NOW(), NOW()),
(12, '竞品对比话术', '我可以帮你客观分析一下市面上的主要选择。和其他机构相比, 我们的最大优势是项目驱动教学——你不是在学语法, 而是在做一个真实的项目。而且我们的导师都是在职工程师, 教的都是企业真正在用的技术。', '沟通', 2, 0, NOW(), NOW()),
(13, '家长沟通话术', '叔叔/阿姨您好, 我是小明同学的规划师。小明在我们这边做了一次编程能力测评, 基础不错, 特别适合往Java后端方向发展。现在Java开发的市场需求非常大, 薪资也高。我们有很多学员毕业后都去了知名互联网公司。', '沟通', 1, 0, NOW(), NOW()),
(14, '试听课邀请', '这周末我们有一节免费的试听课, 讲的是当下最火的Spring Boot微服务开发。老师会带你从零搭建一个完整的Web应用, 大概2小时就能做出成果。你来试试看？不报课也没关系, 就当免费学点东西。', '跟进', 1, 0, NOW(), NOW()),
(15, '试听课后跟进', '同学, 上周末的试听课感觉怎么样？老师讲的内容你能跟上吗？如果你觉得难度适中, 我们可以安排下一阶段的系统学习了。', '跟进', 1, 0, NOW(), NOW()),
(16, '跟进: 家长沟通后', '同学, 上次你说要和家长商量, 家长那边沟通得怎么样了？如果家长有疑问的话, 我可以直接和他们电话聊聊, 帮他们了解课程的价值。', '跟进', 1, 0, NOW(), NOW()),
(17, '跟进: 学习进度检查', '同学这一周学得怎么样？有没有遇到什么卡住的地方？如果有问题可以随时问我, 我帮你拉老师答疑。', '跟进', 1, 0, NOW(), NOW()),
(18, '跟进: 沉默客户激活', '同学好久不见！最近还在学编程吗？我们最近出了一个新课程——AI实战项目班, 挺适合你的。要不要了解一下？就当了解一下行业动态也好~', '跟进', 1, 0, NOW(), NOW()),
(19, '跟进: 犹豫型客户催促', '同学, 其实你现在的学习进度已经很好了, 就差临门一脚投入系统学习了。我们下个月的班级名额已经不多了, 如果你确定想报的话我帮你预留一个位置？', '跟进', 2, 0, NOW(), NOW()),
(20, '跟进: 长期不回消息', '同学, 有一段时间没联系了。不知道你最近学习或者工作方面还顺利吗？我这边随时为你提供帮助, 不管是免费的学习资源还是职业规划建议, 都欢迎随时找我聊聊。', '跟进', 1, 0, NOW(), NOW()),
(21, '跟进: 技术问题解答后', '刚才老师帮你分析了那个数据库的问题, 你按这个思路去调试应该就能解决了。解决了之后告诉我一声, 我们继续推进。加油！', '跟进', 1, 0, NOW(), NOW()),
(22, '促单: 限时优惠', '同学, 这个月我们有个开学季活动, 现在报名可以享受9折优惠。活动到这个月底就结束了, 如果你已经决定要学的话就趁现在报名吧, 能省一笔~', '转化', 1, 0, NOW(), NOW()),
(23, '促单: 名额紧迫', '同学, 你选的这个Java就业班目前只剩下3个名额了。因为我们要保证每个班不超过15人, 确保教学质量。如果你确定要报的话, 我建议尽快确定下来。', '转化', 1, 0, NOW(), NOW()),
(24, '促单: 展示成果', '同学, 这是我们上期学员的就业情况。平均薪资涨了40%, 最高涨了80%。而且每个人都在毕业前就拿到了offer。这些案例都是真实可查的, 我可以把学姐学长的联系方式给你, 你直接问他们。', '转化', 1, 0, NOW(), NOW()),
(25, '促单: 零风险承诺', '我们有一个保障: 如果你学完第一阶段觉得不满意, 可以全额退款。所以你的风险是零——你先来学一个月, 觉得好就继续, 觉得不好就退款, 没有任何损失。', '转化', 1, 0, NOW(), NOW()),
(26, '促单: 职业规划引导', '同学, 如果你现在的目标是进BAT这样的大厂, 那么系统化的学习是必须的。自学虽然省钱, 但时间成本和机会成本很高——你多花一年时间, 就少赚一年的高薪。早入行早积累, 这个投资回报率比你想象的高得多。', '转化', 2, 0, NOW(), NOW()),
(27, '促单: 分期付款方案', '考虑到学生的经济情况, 我们支持3/6/12期分期付款, 而且没有手续费。每个月大概几百块钱, 相当于少买两件衣服或者少吃几顿外卖, 但换来的是终身受益的技能。', '转化', 1, 0, NOW(), NOW()),
(28, '开学前准备提醒', '恭喜同学报名成功！在正式开课前, 你需要准备好: 1) 一台电脑(Windows/Mac都可以) 2) 安装好开发环境(开课前老师会指导) 3) 调整好心态和学习时间。期待在课堂上见到你！', '转化', 1, 0, NOW(), NOW()),
(29, 'Python入门方向建议', 'Python是目前最友好的入门语言, 语法简洁, 应用场景广泛——可以做数据分析、Web开发、自动化运维, 甚至AI开发。我建议你先用Python建立编程思维, 然后再往具体方向深入。', '其他', 1, 0, NOW(), NOW()),
(30, 'Java vs Python选方向', '如果你倾向于进大厂做后端开发, Java是更好的选择, 因为企业级应用Java占绝对主导。如果你更对数据分析和AI感兴趣, Python更适合。两者前景都很好, 看你更喜欢哪个方向的应用场景。', '其他', 1, 0, NOW(), NOW()),
(31, '前端开发学习路线', '前端入门路径: HTML/CSS → JavaScript → 一个框架(Vue或React) → 做一个完整的个人项目 → 学习TypeScript → 深入工程化(Webpack/Vite)。大概4-6个月可以学到能找工作的水平。', '其他', 2, 0, NOW(), NOW()),
(32, '给考研失败同学的建议', '考研没考上不要灰心, 其实很多大公司更看重技术能力和项目经验, 而不是学历。你现在开始学编程, 6个月后就能去找工作了——这比再等一年考研要快得多。而且工作后你发现自己更喜欢哪个方向, 再有针对性地读研也不晚。', '其他', 1, 0, NOW(), NOW()),
(33, '面向大一新生的方向科普', '计算机行业方向大致分为: 前端开发(做网页/App界面)、后端开发(做服务器/数据库)、算法(做AI/数据分析)、运维(做部署/自动化)。大一的时候可以每个方向都尝试一下, 找到自己最喜欢的。', '其他', 1, 0, NOW(), NOW()),
(34, '技术栈阶段: C++学习话术', 'C++是一门经典的编程语言, 虽然入门难一点, 但学会了之后学其他语言会很快。而且很多大公司的底层系统、游戏引擎都是用C++写的, 学会了就业面很广。', '跟进', 1, 0, NOW(), NOW()),
(35, '技术栈阶段: 项目实战推荐', '你现在基础已经ok了, 可以开始做项目了。我推荐你做一个博客系统或者电商网站, 这两个项目能把前后端、数据库串联起来, 对你理解全栈开发帮助很大。', '跟进', 2, 0, NOW(), NOW()),
(36, '课程阶段: 就业方向规划', '你已经学完了技术课程, 现在是时候考虑求职方向了。根据你的技术栈, 我建议你走Java后端方向, 因为你的Spring框架学得最好, 而且这个方向的岗位最多。', '跟进', 1, 0, NOW(), NOW()),
(37, '课程阶段: 简历优化话术', '写简历的时候一定要突出你的项目经验, 而不是学了多少课。比如"独立完成了一个电商后台管理系统, 实现了XXX功能, 解决了XXX技术难题"。数字和结果比描述更有说服力。', '跟进', 1, 0, NOW(), NOW()),
(38, '处理客户投诉', '非常抱歉给你带来了不好的体验。问题我已经记录下来了, 我会第一时间协调老师帮你解决。你的学习效果和体验是我们最关心的, 请放心, 我们一定会妥善处理。', '沟通', 1, 0, NOW(), NOW()),
(39, '跟进: 客户转介绍请求', '同学, 如果你身边有朋友也对编程感兴趣, 可以推荐过来哦。我们有推荐奖励——每成功推荐一位同学报课, 可以减免你下阶段的学费。', '跟进', 2, 0, NOW(), NOW()),
(40, '新人话术: 从0-1建立信任', '同学你好, 我是新加入团队的。虽然经验不算多, 但我很愿意花时间帮你解决问题。你可以把我当成你的学习伙伴, 有任何问题随时找我, 我不懂的帮你问大牛~', '邀约', 5, 0, NOW(), NOW()),
(41, '应对"我觉得自学就够了"', '自学当然也是可以的, 很多人也是自学成功的。不过自学最大的问题是效率——你可能会花很多时间踩坑、找资料、判断方向。而我们的课程把最优的学习路径和项目经验都整理好了, 你可以把时间花在真正重要的地方: 写代码和做项目。', '沟通', 3, 0, NOW(), NOW()),
(42, '应对"培训机构都是骗人的"', '你说得对, 市面上确实有一些不靠谱的机构。这也是为什么我们特别注重透明——你可以随时来校区参观、旁听课程、和学员聊天。我们觉得好的培训是经得起考察的, 你不用担心。', '沟通', 1, 0, NOW(), NOW()),
(43, '应对"我想再考虑考虑"', '当然可以慢慢考虑。不过在你考虑的同时, 我想帮你梳理一下你在考虑什么——是价格问题、时间问题、还是对课程效果的疑问？把问题具体化我们才能一起解决。', '跟进', 1, 0, NOW(), NOW()),
(44, 'AI方向科普话术', 'AI是现在最火的方向, 但新人很容易被概念吓到。其实入门AI不需要太多数学基础——先学会Python, 然后学个NumPy和Pandas, 再做个简单的数据分析项目, 你就入门了。后面的深度学习再慢慢学。', '其他', 1, 0, NOW(), NOW()),
(45, '寒冬期客户维护', '同学最近怎么样？天气冷了注意保暖。学习也别太拼, 注意休息。如果最近学习压力大可以找我聊聊, 不一定是课程问题, 随便聊也可以~', '跟进', 5, 0, NOW(), NOW()),
(46, '给转行者的鼓励话术', '转行确实不容易, 但你要知道我们接触的最成功的那些学员, 很多都是转行过来的。因为他们有更强的动力和更清晰的目标。你现在走的这条路已经有很多人走过了, 是可行的, 加油！', '其他', 4, 0, NOW(), NOW()),
(47, '促单: 节假日活动', '同学, 五一劳动节快乐！我们这边有个节日特别优惠——现在报名可以享受85折优惠+赠送一门价值1999的项目实战课。活动只到假期结束, 有意向的话可以抓紧了解一下~', '转化', 1, 0, NOW(), NOW()),
(48, '促单: 春节前最后一波', '同学, 春节前这是最后一期班级了。如果你打算年后开始学的话, 其实现在报名更划算——价格还是按今年的标准, 但课是年后上, 相当于你用今年的价格买了明年的课程。', '转化', 1, 0, NOW(), NOW()),
(49, '介绍我们的教学模式', '我们采用"翻转课堂"模式: 课前看录播视频预习, 课上是项目实战和答疑。这样你能根据自己的节奏学习理论知识, 而把宝贵的课堂时间用在动手写代码和解决真实问题上。', '沟通', 1, 0, NOW(), NOW()),
(50, '暖场: 初次电话沟通模板', '喂, 你好, 是XX同学吗？我是YouSells的学习规划师。你之前在XXX上留了联系方式, 说对编程感兴趣。我现在方便和你聊两分钟吗？主要是想了解一下你目前的学习情况和目标, 看看我们能不能帮到你。', '邀约', 1, 0, NOW(), NOW());

