INSERT INTO weekly_reports (week_key, week_start, week_end, user_id, new_customer_count, follow_up_count, progress_advance_count, converted_count, task_completed_count, summary, issues, next_week_plan, created_at, updated_at) VALUES
('2026-W20', DATE_SUB(CURDATE(), INTERVAL 14 DAY), DATE_SUB(CURDATE(), INTERVAL 8 DAY), 1, 3, 18, 6, 2, 6, '本周整体推进顺利。重点推进了王同学和张同学进入课程阶段, 标志着两个高意向客户的转化完成。同时通过校园地推新增了3个客户——褚同学、卫同学和蒋同学, 虽然都处于早期阶段但潜力不错。内部完成了客户跟进SOP的初稿和攻略区分类整理, 为后续标准化操作打下了基础。', '冯同学持续联系不上, 已尝试多种渠道。考研季对培训行业的淡季效应开始显现, 需要考虑应对策略。', '1. 跟进王同学和张同学的开课事宜\n2. 继续尝试联系冯同学(通过家长渠道)\n3. 完善SOP文档并分享给团队\n4. 准备周末的招生宣讲\n5. 安排团队周会回顾本周工作', NOW(), NOW()),
('2026-W21', DATE_SUB(CURDATE(), INTERVAL 7 DAY), CURDATE(), 1, 4, 22, 8, 3, 7, '本周是转化效果极好的一周——孙同学、吴同学、郑同学先后报课, 赵同学也完成了开课, 总计转化4人。通过企业合作拓展, 为学员争取到了实习机会。P3智能化升级规划启动了, 这对提升团队整体工作效率会有很大帮助。', '周同学虽然有了进步但仍处于缓慢推进状态, 需要更加耐心。个别同学(冯同学)明确表示因考研暂不报课, 建议记录为长期跟踪。', '1. 签署企业合作协议\n2. 推进P3规划到具体任务分配阶段\n3. 为新报课同学安排导师和班级\n4. 完成月度数据汇总\n5. 和冯同学约定下次联系时间(考完研后)', NOW(), NOW()),
('2026-W21', DATE_SUB(CURDATE(), INTERVAL 7 DAY), CURDATE(), 2, 2, 10, 4, 1, 3, '本周主要推进了蒋同学和杨同学的入门学习, 两位同学都从职规进入了技术栈阶段。知乎和抖音的引流效果持续稳定, 新增了两个客户。但遗憾的是秦同学确认流失了, 分析原因可能和其他机构的竞争有关。', '秦同学流失的原因需要深入分析。韩同学的畏难情绪虽然有所缓解但仍需持续关注。', '1. 为沈同学制定高阶定制化方案\n2. 跟进蒋同学和家长沟通结果\n3. 优化防流失话术和机制\n4. 继续知乎内容运营\n5. 完善新客户接待流程', NOW(), NOW()),
('2026-W21', DATE_SUB(CURDATE(), INTERVAL 7 DAY), CURDATE(), 3, 1, 5, 1, 0, 2, '作为新加入的成员, 本周主要在熟悉业务流程和客户资料。独立跟进了尤同学, 同学开始学C语言了。吕同学基础很好但需要对AI方向做更现实的预期管理。', '刚上手有些流程还不太熟悉, 需要继续学习。吕同学对AI期望值过高, 需要妥善引导。', '1. 完成客户沟通SOP的学习\n2. 为尤同学制定C语言学习计划\n3. 和吕同学做一次详细的AI方向规划\n4. 准备何同学的试听课安排\n5. 整理技术问答贡献到话术库', NOW(), NOW());

-- ============================================================
-- Part 7: 攻略区话题 (让项目更完整)
-- ============================================================
INSERT INTO topic_replies (topic_id, user_id, content, is_solution, created_at) VALUES
-- 对话题1的回复
(1, 2, '我觉得对于大一新生, 关键是要降低门槛, 让他们先动手写出第一个Hello World。我当时就是被"写出代码就能运行"的感觉吸引进来的。', 0, DATE_SUB(NOW(), INTERVAL 5 DAY)),
(1, 3, '建议从Python入手, 语法简单直观, 而且马上就能看到效果。我之前带过一个学弟, 第一天就能用Python写个计算器, 特别有成就感。', 0, DATE_SUB(NOW(), INTERVAL 4 DAY)),
(1, 1, '大家说的都很好。我的经验是: 第一步不要讲太多理论, 直接让他们写代码。第二是多展示编程能做什么——做个网页、爬个数据、画个图表, 让他们看到成果。第三是群体效应——找个学习搭子一起学。', 1, DATE_SUB(NOW(), INTERVAL 3 DAY)),
-- 对话题2的回复
(2, 3, '食堂地推的关键是快——不能在吃饭时间打扰太久。三句话: 你好+你是什么专业的+有兴趣了解一下编程吗。留下微信就行, 不要当场推销。', 0, DATE_SUB(NOW(), INTERVAL 4 DAY)),
(2, 4, '建议准备一个小道具——比如一块小白板, 上面写着"免费编程能力测评", 比口头说更有吸引力。', 0, DATE_SUB(NOW(), INTERVAL 3 DAY)),
(2, 1, '补充一个技巧: 不要站在食堂门口, 站在出口。因为进门的时候同学急着吃饭, 出门的时候比较放松, 更愿意停下来聊天。', 1, DATE_SUB(NOW(), INTERVAL 2 DAY)),
-- 对话题3的回复
(3, 5, '关于这个问题, 我觉得应该先了解客户当前的水平。如果是零基础, 建议从HTML/CSS入门, 做出一个静态页面建立信心。如果是科班生, 可以直接讲项目实战。', 0, DATE_SUB(NOW(), INTERVAL 2 DAY)),
(10, 5, '我补充一个思路: 针对不同阶段做不同的学习路径图。职规阶段的路线图以"认识行业"为目的, 技术栈阶段以"建立能力"为目的, 课程阶段以"求职就业"为目的。', 0, DATE_SUB(NOW(), INTERVAL 1 DAY)),
(11, 2, '分享我用的一个类比: 编程就像学做菜——自学是自己看菜谱摸索, 培训是有大厨手把手教你。都能学会做菜, 但速度和成品的品质差别很大。', 0, DATE_SUB(NOW(), INTERVAL 2 DAY));
